import React, { useState } from 'react';

const App = () => {
  const [price, setPrice] = useState(99.99);
  const handleToggle = () => {
    if (price === 99.99) {
      setPrice(59.99);
    } else {
      setPrice(99.99);
    }
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 flex items-center justify-center">
        <div className="bg-[#C06C88] p-2 rounded-md">
          <p>Product Image</p>
        </div>
        <p className="ml-4">$99.99</p>
        <button className="ml-4" onClick={handleToggle}>Toggle Price</button>
      </div>
    </div>
  );
};

export default App;
